     1→'use client';
     2→
     3→/**
     4→ * FocusToolLayout - Fullscreen layout for working with tools
     5→ *
     6→ * Layout (Issue #102):
     7→ * - Left: Minimized sidebar (icons only, expandable on hover/click)
     8→ * - Center (70%): Tool panel (mindmap, quiz, etc.)
     9→ * - Right (30%): Maestro panel with avatar, voice UI, chat
    10→ * - Mobile: Right panel becomes bottom sheet
    11→ * - ESC to exit
    12→ */
    13→
    14→import { useEffect, useCallback, useState, useRef } from 'react';
    15→import { motion, AnimatePresence } from 'framer-motion';
    16→import {
    17→  X, Loader2, Send, Mic, MicOff, Phone, PhoneOff, Volume2,
    18→  GraduationCap, BookOpen, Brain, Trophy, Settings, Network,
    19→  Target, FileText, PanelLeftOpen, PanelLeftClose,
    20→} from 'lucide-react';
    21→import { Button } from '@/components/ui/button';
    22→import { ToolPanel } from './tool-panel';
    23→import { useUIStore, useSettingsStore } from '@/lib/stores/app-store';
    24→import { getMaestroById } from '@/data';
    25→import { getSupportTeacherById } from '@/data/support-teachers';
    26→import { useVoiceSession } from '@/lib/hooks/use-voice-session';
    27→import { logger } from '@/lib/logger';
    28→import type { ToolType } from '@/types/tools';
    29→import type { Maestro, SupportTeacher, Subject } from '@/types';
    30→import { cn } from '@/lib/utils';
    31→
    32→// Map tool types to suggested maestros (for future use)
    33→const _TOOL_TO_MAESTRO: Record<ToolType, string> = {
    34→  mindmap: 'melissa', // Coach for general organization
    35→  quiz: 'melissa',
    36→  flashcard: 'melissa',
    37→  summary: 'melissa',
    38→  demo: 'ada', // Ada for demos/coding
    39→  diagram: 'euclid', // Euclid for diagrams
    40→  timeline: 'herodotus', // Herodotus for timelines
    41→  formula: 'euclid',
    42→  chart: 'euclid',
    43→  search: 'melissa',
    44→  webcam: 'melissa',
    45→  pdf: 'melissa',
    46→  homework: 'melissa',
    47→};
    48→
    49→// Map subjects to maestros (for future use)
    50→const _SUBJECT_TO_MAESTRO: Record<string, string> = {
    51→  mathematics: 'euclid',
    52→  math: 'euclid',
    53→  matematica: 'euclid',
    54→  history: 'herodotus',
    55→  storia: 'herodotus',
    56→  italian: 'manzoni',
    57→  italiano: 'manzoni',
    58→  english: 'shakespeare',
    59→  inglese: 'shakespeare',
    60→  physics: 'feynman',
    61→  fisica: 'feynman',
    62→  chemistry: 'curie',
    63→  chimica: 'curie',
    64→  biology: 'darwin',
    65→  biologia: 'darwin',
    66→  scienze: 'darwin',
    67→  geography: 'humboldt',
    68→  geografia: 'humboldt',
    69→  art: 'davinci',
    70→  arte: 'davinci',
    71→  music: 'mozart',
    72→  musica: 'mozart',
    73→  philosophy: 'socrates',
    74→  filosofia: 'socrates',
    75→  economics: 'smith',
    76→  economia: 'smith',
    77→  civics: 'cicero',
    78→  educazione_civica: 'cicero',
    79→  pe: 'hippocrates',
    80→  educazione_fisica: 'hippocrates',
    81→  coding: 'ada',
    82→  informatica: 'ada',
    83→  storytelling: 'chris',
    84→};
    85→
    86→interface Message {
    87→  id: string;
    88→  role: 'user' | 'assistant';
    89→  content: string;
    90→  timestamp: Date;
    91→}
    92→
    93→// Map function names to tool types
    94→const FUNCTION_NAME_TO_TOOL_TYPE: Record<string, ToolType> = {
    95→  create_mindmap: 'mindmap',
    96→  create_quiz: 'quiz',
    97→  create_demo: 'demo',
    98→  web_search: 'search',
    99→  create_flashcards: 'flashcard',
   100→  create_diagram: 'diagram',
   101→  create_timeline: 'timeline',
   102→  create_summary: 'summary',
   103→  open_student_summary: 'summary',
   104→};
   105→
   106→export function FocusToolLayout() {
   107→  const { focusMode, focusToolType, focusMaestroId, focusInteractionMode, focusTool, setFocusTool, exitFocusMode } = useUIStore();
   108→  const { studentProfile } = useSettingsStore();
   109→
   110→  const [messages, setMessages] = useState<Message[]>([]);
   111→  const [input, setInput] = useState('');
   112→  const [isLoading, setIsLoading] = useState(false);
   113→  const [isVoiceActive, setIsVoiceActive] = useState(false);
   114→  const [connectionInfo, setConnectionInfo] = useState<{ provider: 'azure'; proxyPort: number; configured: boolean } | null>(null);
   115→  const [configError, setConfigError] = useState<string | null>(null);
   116→  const [sidebarExpanded, setSidebarExpanded] = useState(false);
   117→  const [rightPanelCollapsed, setRightPanelCollapsed] = useState(false);
   118→  const messagesEndRef = useRef<HTMLDivElement>(null);
   119→  const inputRef = useRef<HTMLInputElement>(null);
   120→  const lastTranscriptIdRef = useRef<string | null>(null);
   121→
   122→  // Sidebar nav items for minimized sidebar
   123→  const sidebarItems = [
   124→    { id: 'maestri', label: 'Professori', icon: GraduationCap },
   125→    { id: 'quiz', label: 'Quiz', icon: Brain },
   126→    { id: 'flashcards', label: 'Flashcards', icon: BookOpen },
   127→    { id: 'mindmaps', label: 'Mappe Mentali', icon: Network },
   128→    { id: 'summaries', label: 'Riassunti', icon: FileText },
   129→    { id: 'homework', label: 'Materiali', icon: Target },
   130→    { id: 'progress', label: 'Progressi', icon: Trophy },
   131→    { id: 'settings', label: 'Impostazioni', icon: Settings },
   132→  ];
   133→
   134→  // Determine which maestro/coach to use
   135→  const getMaestroOrCoach = useCallback((): Maestro | SupportTeacher | null => {
   136→    // If specific maestro requested
   137→    if (focusMaestroId) {
   138→      const maestro = getMaestroById(focusMaestroId);
   139→      if (maestro) return maestro;
   140→
   141→      // Check if it's a coach
   142→      const coach = getSupportTeacherById(focusMaestroId as 'melissa' | 'roberto' | 'chiara' | 'andrea' | 'favij');
   143→      if (coach) return coach;
   144→
   145→      // Character ID provided but not found - log actionable error
   146→      logger.error('Focus mode character not found. Verify character ID exists in maestri-full.ts or support-teachers.ts', {
   147→        focusMaestroId,
   148→        action: 'falling back to default coach'
   149→      });
   150→    }
   151→
   152→    // If no focusMaestroId provided, warn about missing maestro selection
   153→    if (!focusMaestroId) {
   154→      logger.warn('Focus mode entered without maestro selection, using default coach');
   155→    }
   156→
   157→    // Fallback to coach based on preference
   158→    const preferredCoach = studentProfile?.preferredCoach || 'melissa';
   159→    const coach = getSupportTeacherById(preferredCoach);
   160→    if (coach) return coach;
   161→
   162→    return null;
   163→  }, [focusMaestroId, studentProfile?.preferredCoach]);
   164→
   165→  const character = getMaestroOrCoach();
   166→
   167→  // Helper to get display properties from either Maestro or SupportTeacher
   168→  const getCharacterProps = (char: Maestro | SupportTeacher | null) => {
   169→    if (!char) return null;
   170→    // Both Maestro and SupportTeacher have 'name' property
   171→    return {
   172→      name: char.name,
   173→      avatar: char.avatar || '/avatars/default.jpg',
   174→      color: char.color,
   175→      systemPrompt: char.systemPrompt,
   176→      greeting: char.greeting,
   177→    };
   178→  };
   179→
   180→  const characterProps = getCharacterProps(character);
   181→
   182→  // Voice session hook - must be after character is defined
   183→  const {
   184→    isConnected: voiceConnected,
   185→    isSpeaking,
   186→    isMuted,
   187→    inputLevel,
   188→    connectionState,
   189→    connect: voiceConnect,
   190→    disconnect: voiceDisconnect,
   191→    toggleMute,
   192→    sessionId: voiceSessionId,
   193→  } = useVoiceSession({
   194→    onError: (error) => {
   195→      const message = error instanceof Error ? error.message : String(error);
   196→      logger.error('Voice session error in focus mode', { message });
   197→      setConfigError(message || 'Errore di connessione vocale');
   198→    },
   199→    onTranscript: (role, text) => {
   200→      // Add voice transcripts to messages
   201→      const transcriptId = `voice-${role}-${Date.now()}`;
   202→
   203→      // Avoid duplicate transcripts
   204→      if (lastTranscriptIdRef.current === text.substring(0, 50)) {
   205→        return;
   206→      }
   207→      lastTranscriptIdRef.current = text.substring(0, 50);
   208→
   209→      setMessages(prev => [...prev, {
   210→        id: transcriptId,
   211→        role,
   212→        content: text,
   213→        timestamp: new Date(),
   214→      }]);
   215→    },
   216→  });
   217→
   218→  // Fetch voice connection info on mount
   219→  useEffect(() => {
   220→    async function fetchConnectionInfo() {
   221→      try {
   222→        const response = await fetch('/api/realtime/token');
   223→        const data = await response.json();
   224→        if (data.error) {
   225→          logger.error('Voice API error', { error: data.error });
   226→          setConfigError(data.message || 'Servizio vocale non configurato');
   227→          return;
   228→        }
   229→        setConnectionInfo(data);
   230→      } catch (error) {
   231→        logger.error('Failed to get voice connection info', { error: String(error) });
   232→        setConfigError('Impossibile connettersi al servizio vocale');
   233→      }
   234→    }
   235→    if (focusMode) {
   236→      fetchConnectionInfo();
   237→    }
   238→  }, [focusMode]);
   239→
   240→  // Auto-start voice if interaction mode is 'voice'
   241→  useEffect(() => {
   242→    if (focusMode && focusInteractionMode === 'voice' && connectionInfo && !isVoiceActive) {
   243→      setIsVoiceActive(true);
   244→    }
   245→  }, [focusMode, focusInteractionMode, connectionInfo, isVoiceActive]);
   246→
   247→  // Connect to voice when activated
   248→  useEffect(() => {
   249→    if (!isVoiceActive || !connectionInfo || connectionState !== 'idle' || !character) return;
   250→
   251→    const startVoice = async () => {
   252→      setConfigError(null);
   253→      try {
   254→        // Check if character is a SupportTeacher (has voice property directly)
   255→        const isSupportTeacher = 'voice' in character && 'voiceInstructions' in character;
   256→        // Create a maestro-compatible object for the voice session
   257→        const maestroForVoice = {
   258→          id: character.id,
   259→          name: characterProps?.name || 'Coach',
   260→          subject: ('subject' in character ? character.subject : 'general') as Subject,
   261→          specialty: '',
   262→          voice: isSupportTeacher ? (character as SupportTeacher).voice : 'alloy' as const,
   263→          voiceInstructions: isSupportTeacher ? (character as SupportTeacher).voiceInstructions : 'Parla in modo chiaro e amichevole.',
   264→          teachingStyle: 'Interattivo e coinvolgente',
   265→          avatar: characterProps?.avatar || '/avatars/default.jpg',
   266→          color: characterProps?.color || '#3b82f6',
   267→          systemPrompt: characterProps?.systemPrompt || '',
   268→          greeting: characterProps?.greeting || '',
   269→        };
   270→        await voiceConnect(maestroForVoice, connectionInfo);
   271→      } catch (error) {
   272→        logger.error('Voice connection failed', { error: String(error) });
   273→        if (error instanceof DOMException && error.name === 'NotAllowedError') {
   274→          setConfigError('Microfono non autorizzato. Abilita il microfono nelle impostazioni del browser.');
   275→        } else {
   276→          setConfigError('Errore di connessione vocale');
   277→        }
   278→        setIsVoiceActive(false);
   279→      }
   280→    };
   281→
   282→    startVoice();
   283→  }, [isVoiceActive, connectionInfo, connectionState, character, characterProps, voiceConnect]);
   284→
   285→  // Handle voice toggle
   286→  const handleVoiceToggle = useCallback(() => {
   287→    if (isVoiceActive) {
   288→      voiceDisconnect();
   289→      setIsVoiceActive(false);
   290→    } else {
   291→      setIsVoiceActive(true);
   292→    }
   293→  }, [isVoiceActive, voiceDisconnect]);
   294→
   295→  // ESC key handler
   296→  useEffect(() => {
   297→    const handleKeyDown = (e: KeyboardEvent) => {
   298→      if (e.key === 'Escape' && focusMode) {
   299→        exitFocusMode();
   300→      }
   301→    };
   302→
   303→    window.addEventListener('keydown', handleKeyDown);
   304→    return () => window.removeEventListener('keydown', handleKeyDown);
   305→  }, [focusMode, exitFocusMode]);
   306→
   307→  // Auto-scroll messages
   308→  useEffect(() => {
   309→    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
   310→  }, [messages]);
   311→
   312→  // Focus input when mode activates
   313→  useEffect(() => {
   314→    if (focusMode) {
   315→      inputRef.current?.focus();
   316→    }
   317→  }, [focusMode]);
   318→
   319→  // Initial greeting message
   320→  useEffect(() => {
   321→    if (focusMode && characterProps && messages.length === 0) {
   322→      const toolNames: Record<ToolType, string> = {
   323→        mindmap: 'mappa mentale',
   324→        quiz: 'quiz',
   325→        flashcard: 'flashcard',
   326→        summary: 'riassunto',
   327→        demo: 'demo interattiva',
   328→        diagram: 'diagramma',
   329→        timeline: 'linea del tempo',
   330→        formula: 'formula',
   331→        chart: 'grafico',
   332→        search: 'ricerca',
   333→        webcam: 'foto',
   334→        pdf: 'PDF',
   335→        homework: 'compiti',
   336→      };
   337→
   338→      const toolName = focusToolType ? toolNames[focusToolType] : 'strumento';
   339→
   340→      setMessages([{
   341→        id: 'greeting',
   342→        role: 'assistant',
   343→        content: `Ciao! Sono ${characterProps.name}. Creiamo insieme una ${toolName}! Di che argomento vuoi parlare?`,
   344→        timestamp: new Date(),
   345→      }]);
   346→    }
   347→  }, [focusMode, characterProps, focusToolType, messages.length]);
   348→
   349→  // Handle sending message
   350→  const handleSend = useCallback(async () => {
   351→    if (!input.trim() || isLoading || !character || !characterProps) return;
   352→
   353→    const userMessage = input.trim();
   354→    setInput('');
   355→    setIsLoading(true);
   356→
   357→    const newUserMessage: Message = {
   358→      id: `user-${Date.now()}`,
   359→      role: 'user',
   360→      content: userMessage,
   361→      timestamp: new Date(),
   362→    };
   363→
   364→    setMessages(prev => [...prev, newUserMessage]);
   365→
   366→    try {
   367→      const response = await fetch('/api/chat', {
   368→        method: 'POST',
   369→        headers: { 'Content-Type': 'application/json' },
   370→        body: JSON.stringify({
   371→          messages: [
   372→            ...messages.map(m => ({ role: m.role, content: m.content })),
   373→            { role: 'user', content: userMessage },
   374→          ],
   375→          systemPrompt: characterProps.systemPrompt,
   376→          maestroId: character.id,
   377→          enableTools: true,
   378→          requestedTool: focusToolType,
   379→        }),
   380→      });
   381→
   382→      if (!response.ok) throw new Error('Failed to send message');
   383→
   384→      const data = await response.json();
   385→
   386→      const assistantMessage: Message = {
   387→        id: `assistant-${Date.now()}`,
   388→        role: 'assistant',
   389→        content: data.content || '',
   390→        timestamp: new Date(),
   391→      };
   392→
   393→      if (data.content) {
   394→        setMessages(prev => [...prev, assistantMessage]);
   395→      }
   396→
   397→      // Handle tool calls if any
   398→      if (data.toolCalls && data.toolCalls.length > 0) {
   399→        const toolCall = data.toolCalls[0];
   400→        const toolType = FUNCTION_NAME_TO_TOOL_TYPE[toolCall.type] || focusToolType || 'mindmap';
   401→        const toolContent = toolCall.result?.data || toolCall.result || toolCall.arguments;
   402→
   403→        setFocusTool({
   404→          id: toolCall.id || `tool-${Date.now()}`,
   405→          type: toolType,
   406→          status: 'completed',
   407→          progress: 1,
   408→          content: toolContent,
   409→          createdAt: new Date(),
   410→        });
   411→      }
   412→    } catch (error) {
   413→      logger.error('Chat error in focus mode', { error });
   414→      setMessages(prev => [...prev, {
   415→        id: `error-${Date.now()}`,
   416→        role: 'assistant',
   417→        content: 'Mi dispiace, c\'è stato un errore. Riprova!',
   418→        timestamp: new Date(),
   419→      }]);
   420→    } finally {
   421→      setIsLoading(false);
   422→    }
   423→  }, [input, isLoading, character, characterProps, messages, focusToolType, setFocusTool]);
   424→
   425→  const handleKeyPress = (e: React.KeyboardEvent) => {
   426→    if (e.key === 'Enter' && !e.shiftKey) {
   427→      e.preventDefault();
   428→      handleSend();
   429→    }
   430→  };
   431→
   432→  if (!focusMode) return null;
   433→
   434→  // Tool type display name
   435→  const toolNames: Record<ToolType, string> = {
   436→    mindmap: 'Mappa Mentale',
   437→    quiz: 'Quiz',
   438→    flashcard: 'Flashcards',
   439→    summary: 'Riassunto',
   440→    demo: 'Demo Interattiva',
   441→    diagram: 'Diagramma',
   442→    timeline: 'Linea del Tempo',
   443→    formula: 'Formula',
   444→    chart: 'Grafico',
   445→    search: 'Ricerca',
   446→    webcam: 'Foto',
   447→    pdf: 'PDF',
   448→    homework: 'Compiti',
   449→  };
   450→
   451→  return (
   452→    <AnimatePresence>
   453→      <motion.div
   454→        initial={{ opacity: 0 }}
   455→        animate={{ opacity: 1 }}
   456→        exit={{ opacity: 0 }}
   457→        className="fixed inset-0 z-50 bg-white dark:bg-slate-950 flex"
   458→      >
   459→        {/* Left: Minimized Sidebar (Issue #102 - 0.6.1) */}
   460→        <aside
   461→          className={cn(
   462→            'h-full bg-white dark:bg-slate-900 border-r border-slate-200 dark:border-slate-800 transition-all duration-300 flex flex-col',
   463→            sidebarExpanded ? 'w-48' : 'w-14'
   464→          )}
   465→          onMouseEnter={() => setSidebarExpanded(true)}
   466→          onMouseLeave={() => setSidebarExpanded(false)}
   467→        >
   468→          {/* Logo/Toggle */}
   469→          <div className="h-14 flex items-center gap-2 px-2 border-b border-slate-200 dark:border-slate-800 flex-shrink-0">
   470→            {/* Brain Logo */}
   471→            <img
   472→              src="/logo-brain.png"
   473→              alt="MirrorBuddy"
   474→              className="h-8 w-8 object-contain flex-shrink-0"
   475→            />
   476→            {sidebarExpanded && (
   477→              <span className="text-sm font-bold text-slate-800 dark:text-white truncate">
   478→                MirrorBuddy
   479→              </span>
   480→            )}
   481→            <Button
   482→              variant="ghost"
   483→              size="icon-sm"
   484→              onClick={() => setSidebarExpanded(!sidebarExpanded)}
   485→              className="text-slate-500 ml-auto"
   486→              aria-label={sidebarExpanded ? 'Riduci menu' : 'Espandi menu'}
   487→            >
   488→              {sidebarExpanded ? <PanelLeftClose className="h-4 w-4" /> : <PanelLeftOpen className="h-4 w-4" />}
   489→            </Button>
   490→          </div>
   491→
   492→          {/* Nav Items */}
   493→          <nav className="flex-1 py-2 overflow-y-auto">
   494→            {sidebarItems.map((item) => (
   495→              <button
   496→                key={item.id}
   497→                onClick={exitFocusMode}
   498→                className="w-full flex items-center gap-3 px-3 py-2.5 text-slate-600 dark:text-slate-400 hover:bg-slate-100 dark:hover:bg-slate-800 transition-colors group"
   499→                title={item.label}
   500→              >
   501→                <item.icon className="h-5 w-5 flex-shrink-0" />
   502→                {sidebarExpanded && (
   503→                  <span className="text-sm font-medium whitespace-nowrap">{item.label}</span>
   504→                )}
   505→              </button>
   506→            ))}
   507→          </nav>
   508→
   509→          {/* Exit Button */}
   510→          <div className="p-2 border-t border-slate-200 dark:border-slate-800 flex-shrink-0">
   511→            <button
   512→              onClick={exitFocusMode}
   513→              className="w-full flex items-center gap-3 px-3 py-2.5 text-red-600 dark:text-red-400 hover:bg-red-50 dark:hover:bg-red-900/20 rounded-lg transition-colors"
   514→              title="Esci dalla modalità strumento"
   515→            >
   516→              <X className="h-5 w-5 flex-shrink-0" />
   517→              {sidebarExpanded && <span className="text-sm font-medium">Esci</span>}
   518→            </button>
   519→          </div>
   520→        </aside>
   521→
   522→        {/* Center: Tool Panel (Issue #102 - 0.6.3 - 70% width) */}
   523→        <div className={cn(
   524→          'flex-1 h-full overflow-hidden bg-slate-50 dark:bg-slate-900 flex flex-col',
   525→          rightPanelCollapsed ? 'w-full' : 'w-[70%]'
   526→        )}>
   527→          {/* Tool Header */}
   528→          <header className="h-14 flex items-center justify-between px-4 border-b border-slate-200 dark:border-slate-800 bg-white dark:bg-slate-900 flex-shrink-0">
   529→            <div className="flex items-center gap-3">
   530→              <span className="font-semibold text-slate-900 dark:text-white">
   531→                {focusToolType ? toolNames[focusToolType] : 'Strumento'}
   532→              </span>
   533→            </div>
   534→            <div className="flex items-center gap-2">
   535→              <span className="text-xs text-slate-400">ESC per uscire</span>
   536→              <Button
   537→                variant="ghost"
   538→                size="icon-sm"
   539→                onClick={() => setRightPanelCollapsed(!rightPanelCollapsed)}
   540→                className="text-slate-500"
   541→                aria-label={rightPanelCollapsed ? 'Mostra chat' : 'Nascondi chat'}
   542→              >
   543→                {rightPanelCollapsed ? <PanelLeftOpen className="h-4 w-4" /> : <PanelLeftClose className="h-4 w-4" />}
   544→              </Button>
   545→            </div>
   546→          </header>
   547→
   548→          {/* Tool Content */}
   549→          <div className="flex-1 overflow-auto">
   550→            {focusTool ? (
   551→              <ToolPanel
   552→                tool={focusTool}
   553→                maestro={characterProps ? {
   554→                  name: characterProps.name,
   555→                  avatar: characterProps.avatar,
   556→                  color: characterProps.color,
   557→                } : null}
   558→                onClose={() => setFocusTool(null)}
   559→                embedded={true}
   560→                sessionId={voiceSessionId}
   561→              />
   562→            ) : (
   563→              <div className="h-full flex items-center justify-center text-slate-400">
   564→                <div className="text-center">
   565→                  <div className="w-16 h-16 mx-auto mb-4 rounded-full bg-slate-200 dark:bg-slate-800 flex items-center justify-center">
   566→                    <Loader2 className="h-6 w-6 animate-spin" />
   567→                  </div>
   568→                  <p className="text-lg font-medium">In attesa dello strumento...</p>
   569→                  <p className="text-sm mt-1">Parla con {characterProps?.name || 'il coach'} per creare il contenuto</p>
   570→                </div>
   571→              </div>
   572→            )}
   573→          </div>
   574→        </div>
   575→
   576→        {/* Right: Maestro Panel - Compact layout like conversation cards */}
   577→        {!rightPanelCollapsed && (
   578→          <div className="w-[30%] max-w-md h-full flex flex-col border-l border-slate-200 dark:border-slate-800 bg-white dark:bg-slate-900">
   579→            {/* Maestro Header - Same style as conversation header */}
   580→            <div
   581→              className="flex-shrink-0 flex items-center gap-3 px-4 py-3 border-b border-slate-200 dark:border-slate-700"
   582→              style={{ backgroundColor: `${characterProps?.color}10` }}
   583→            >
   584→              {/* Avatar */}
   585→              {characterProps && (
   586→                <>
   587→                  <div className="relative flex-shrink-0">
   588→                    <div
   589→                      className="w-12 h-12 rounded-full overflow-hidden ring-2 ring-offset-2 ring-offset-white dark:ring-offset-slate-900"
   590→                      style={{ borderColor: characterProps.color }}
   591→                    >
   592→                      <div
   593→                        className="w-full h-full bg-cover bg-center"
   594→                        style={{
   595→                          backgroundImage: `url(${characterProps.avatar})`,
   596→                          backgroundColor: characterProps.color,
   597→                        }}
   598→                      />
   599→                    </div>
   600→                    {voiceConnected && (
   601→                      <div className="absolute bottom-0 right-0 w-3 h-3 bg-green-500 border-2 border-white dark:border-slate-900 rounded-full animate-pulse" />
   602→                    )}
   603→                  </div>
   604→
   605→                  {/* Name and status */}
   606→                  <div className="flex-1 min-w-0">
   607→                    <h3 className="font-semibold text-base text-slate-900 dark:text-white truncate">
   608→                      {characterProps.name}
   609→                    </h3>
   610→                    <p className="text-xs text-slate-500 dark:text-slate-400 truncate">
   611→                      {voiceConnected ? (isSpeaking ? 'Sta parlando...' : 'In chiamata') : 'Sono qui per aiutarti'}
   612→                    </p>
   613→                  </div>
   614→
   615→                  {/* Voice call button - inline like conversation header */}
   616→                  <Button
   617→                    variant={voiceConnected ? 'destructive' : 'outline'}
   618→                    size="icon"
   619→                    onClick={handleVoiceToggle}
   620→                    disabled={!!configError && !isVoiceActive}
   621→                    className={cn('relative', voiceConnected && 'animate-pulse')}
   622→                    style={!voiceConnected ? { borderColor: characterProps.color, color: characterProps.color } : undefined}
   623→                    title={voiceConnected ? 'Termina chiamata' : `Chiama ${characterProps.name}`}
   624→                  >
   625→                    {isVoiceActive && !voiceConnected ? (
   626→                      <Loader2 className="h-4 w-4 animate-spin" />
   627→                    ) : voiceConnected ? (
   628→                      <PhoneOff className="h-4 w-4" />
   629→                    ) : (
   630→                      <Phone className="h-4 w-4" />
   631→                    )}
   632→                  </Button>
   633→
   634→                  {/* Mute button when connected */}
   635→                  {voiceConnected && (
   636→                    <Button
   637→                      variant="ghost"
   638→                      size="icon"
   639→                      onClick={toggleMute}
   640→                      className={cn(isMuted && 'text-red-500')}
   641→                      title={isMuted ? 'Attiva microfono' : 'Disattiva microfono'}
   642→                    >
   643→                      {isMuted ? <MicOff className="h-4 w-4" /> : <Mic className="h-4 w-4" />}
   644→                    </Button>
   645→                  )}
   646→                </>
   647→              )}
   648→            </div>
   649→
   650→            {/* Audio level indicator - only when voice active */}
   651→            {voiceConnected && !isMuted && (
   652→              <div className="flex-shrink-0 px-4 py-2 bg-slate-50 dark:bg-slate-800/50 border-b border-slate-200 dark:border-slate-700">
   653→                <div className="flex items-center gap-2">
   654→                  <Volume2 className="h-3 w-3 text-slate-400" />
   655→                  <div className="flex-1 h-1.5 bg-slate-200 dark:bg-slate-700 rounded-full overflow-hidden">
   656→                    <div
   657→                      className="h-full bg-green-500 transition-all duration-75"
   658→                      style={{ width: `${Math.min(inputLevel * 100, 100)}%` }}
   659→                    />
   660→                  </div>
   661→                </div>
   662→              </div>
   663→            )}
   664→
   665→            {/* Chat Messages */}
   666→            <div className="flex-1 overflow-y-auto p-3 space-y-3">
   667→              {messages.map((message) => (
   668→                <div
   669→                  key={message.id}
   670→                  className={cn(
   671→                    'flex',
   672→                    message.role === 'user' ? 'justify-end' : 'justify-start'
   673→                  )}
   674→                >
   675→                  <div
   676→                    className={cn(
   677→                      'max-w-[85%] rounded-2xl px-4 py-2.5 shadow-sm',
   678→                      message.role === 'user'
   679→                        ? 'text-white rounded-br-sm'
   680→                        : 'bg-slate-100 dark:bg-slate-800 text-slate-900 dark:text-slate-100 rounded-bl-sm'
   681→                    )}
   682→                    style={
   683→                      message.role === 'user'
   684→                        ? { backgroundColor: characterProps?.color || '#3b82f6' }
   685→                        : undefined
   686→                    }
   687→                  >
   688→                    <p className="text-sm whitespace-pre-wrap leading-relaxed">{message.content}</p>
   689→                  </div>
   690→                </div>
   691→              ))}
   692→              {isLoading && (
   693→                <div className="flex justify-start">
   694→                  <div className="bg-slate-100 dark:bg-slate-800 rounded-2xl rounded-bl-sm px-4 py-2.5 shadow-sm">
   695→                    <Loader2 className="h-4 w-4 animate-spin text-slate-400" />
   696→                  </div>
   697→                </div>
   698→              )}
   699→              <div ref={messagesEndRef} />
   700→            </div>
   701→
   702→            {/* Chat Input */}
   703→            <div className="flex-shrink-0 p-3 border-t border-slate-200 dark:border-slate-800 bg-white dark:bg-slate-900">
   704→              <div className="flex items-center gap-2">
   705→                <input
   706→                  ref={inputRef}
   707→                  type="text"
   708→                  value={input}
   709→                  onChange={(e) => setInput(e.target.value)}
   710→                  onKeyDown={handleKeyPress}
   711→                  placeholder={`Scrivi a ${characterProps?.name || 'Coach'}...`}
   712→                  className="flex-1 px-4 py-2.5 bg-slate-100 dark:bg-slate-800 rounded-xl border-0 focus:ring-2 outline-none text-sm transition-all"
   713→                  style={{
   714→                    '--tw-ring-color': characterProps?.color || '#3b82f6'
   715→                  } as React.CSSProperties}
   716→                  disabled={isLoading}
   717→                />
   718→                <Button
   719→                  size="icon"
   720→                  onClick={handleSend}
   721→                  disabled={!input.trim() || isLoading}
   722→                  className="flex-shrink-0 shadow-sm"
   723→                  style={{
   724→                    backgroundColor: characterProps?.color || '#3b82f6',
   725→                  }}
   726→                >
   727→                  {isLoading ? <Loader2 className="h-4 w-4 animate-spin" /> : <Send className="h-4 w-4" />}
   728→                </Button>
   729→              </div>
   730→            </div>
   731→          </div>
   732→        )}
   733→      </motion.div>
   734→    </AnimatePresence>
   735→  );
   736→}
