     1→'use client';
     2→
     3→/**
     4→ * ToolMaestroSelectionDialog - Modal for selecting subject/maestro before entering tool focus mode
     5→ * Shows subject selection, then maestro selection for that subject
     6→ */
     7→
     8→import { useState, useCallback, useEffect, useRef } from 'react';
     9→import { motion, AnimatePresence } from 'framer-motion';
    10→import {
    11→  GraduationCap,
    12→  BookOpen,
    13→  ArrowRight,
    14→  ArrowLeft,
    15→  X,
    16→  Mic,
    17→  MessageSquare,
    18→} from 'lucide-react';
    19→import Image from 'next/image';
    20→import { Button } from '@/components/ui/button';
    21→import { cn } from '@/lib/utils';
    22→import { getMaestriBySubject, getAllSubjects, maestri as allMaestri } from '@/data';
    23→import type { Subject, Maestro } from '@/types';
    24→import type { ToolType } from '@/types/tools';
    25→
    26→// Italian labels for subjects
    27→const SUBJECT_LABELS: Record<string, string> = {
    28→  mathematics: 'Matematica',
    29→  physics: 'Fisica',
    30→  chemistry: 'Chimica',
    31→  biology: 'Biologia',
    32→  history: 'Storia',
    33→  geography: 'Geografia',
    34→  italian: 'Italiano',
    35→  english: 'Inglese',
    36→  art: 'Arte',
    37→  music: 'Musica',
    38→  civics: 'Educazione Civica',
    39→  economics: 'Economia',
    40→  computerScience: 'Informatica',
    41→  health: 'Salute',
    42→  philosophy: 'Filosofia',
    43→  internationalLaw: 'Diritto Internazionale',
    44→  astronomy: 'Astronomia',
    45→  'computer-science': 'Informatica',
    46→  'civic-education': 'Educazione Civica',
    47→  science: 'Scienze',
    48→  storytelling: 'Storytelling',
    49→  'physical-education': 'Educazione Fisica',
    50→};
    51→
    52→// Tool type labels in Italian
    53→const TOOL_LABELS: Record<ToolType, string> = {
    54→  mindmap: 'Mappa Mentale',
    55→  quiz: 'Quiz',
    56→  flashcard: 'Flashcard',
    57→  summary: 'Riassunto',
    58→  demo: 'Demo Interattiva',
    59→  diagram: 'Diagramma',
    60→  timeline: 'Linea del Tempo',
    61→  formula: 'Formula',
    62→  chart: 'Grafico',
    63→  search: 'Ricerca',
    64→  webcam: 'Foto',
    65→  pdf: 'PDF',
    66→  homework: 'Compiti',
    67→};
    68→
    69→const getSubjectLabel = (subject: string): string => {
    70→  return SUBJECT_LABELS[subject] || subject.charAt(0).toUpperCase() + subject.slice(1).replace(/-/g, ' ');
    71→};
    72→
    73→interface ToolMaestroSelectionDialogProps {
    74→  isOpen: boolean;
    75→  toolType: ToolType;
    76→  onConfirm: (maestro: Maestro, mode: 'voice' | 'chat') => void;
    77→  onClose: () => void;
    78→}
    79→
    80→type Step = 'subject' | 'maestro' | 'mode';
    81→
    82→export function ToolMaestroSelectionDialog({
    83→  isOpen,
    84→  toolType,
    85→  onConfirm,
    86→  onClose,
    87→}: ToolMaestroSelectionDialogProps) {
    88→  const [step, setStep] = useState<Step>('subject');
    89→  const [selectedSubject, setSelectedSubject] = useState<Subject | null>(null);
    90→  const [selectedMaestro, setSelectedMaestro] = useState<Maestro | null>(null);
    91→  const dialogRef = useRef<HTMLDivElement>(null);
    92→  const previousFocusRef = useRef<HTMLElement | null>(null);
    93→
    94→  const allSubjects = getAllSubjects();
    95→
    96→  // Focus trap and keyboard handling
    97→  useEffect(() => {
    98→    if (!isOpen) return;
    99→
   100→    // Store previous focus
   101→    previousFocusRef.current = document.activeElement as HTMLElement;
   102→
   103→    // Focus the dialog
   104→    dialogRef.current?.focus();
   105→
   106→    // Handle Escape key
   107→    const handleKeyDown = (e: KeyboardEvent) => {
   108→      if (e.key === 'Escape') {
   109→        e.preventDefault();
   110→        onClose();
   111→      }
   112→
   113→      // Focus trap - keep focus within dialog
   114→      if (e.key === 'Tab' && dialogRef.current) {
   115→        const focusableElements = dialogRef.current.querySelectorAll<HTMLElement>(
   116→          'button, [href], input, select, textarea, [tabindex]:not([tabindex="-1"])'
   117→        );
   118→        const firstElement = focusableElements[0];
   119→        const lastElement = focusableElements[focusableElements.length - 1];
   120→
   121→        if (e.shiftKey && document.activeElement === firstElement) {
   122→          e.preventDefault();
   123→          lastElement?.focus();
   124→        } else if (!e.shiftKey && document.activeElement === lastElement) {
   125→          e.preventDefault();
   126→          firstElement?.focus();
   127→        }
   128→      }
   129→    };
   130→
   131→    document.addEventListener('keydown', handleKeyDown);
   132→
   133→    return () => {
   134→      document.removeEventListener('keydown', handleKeyDown);
   135→      // Restore focus when dialog closes
   136→      previousFocusRef.current?.focus();
   137→    };
   138→  }, [isOpen, onClose]);
   139→  const availableMaestri = selectedSubject ? getMaestriBySubject(selectedSubject) : [];
   140→
   141→  const toolLabel = TOOL_LABELS[toolType] || toolType;
   142→
   143→  const handleSubjectSelect = useCallback((subject: Subject) => {
   144→    setSelectedSubject(subject);
   145→    const maestri = getMaestriBySubject(subject);
   146→    if (maestri.length === 1) {
   147→      // Auto-select if only one maestro
   148→      setSelectedMaestro(maestri[0]);
   149→      setStep('mode');
   150→    } else if (maestri.length > 1) {
   151→      setStep('maestro');
   152→    } else {
   153→      // No maestro for this subject, show all maestri
   154→      setStep('maestro');
   155→    }
   156→  }, []);
   157→
   158→  const handleMaestroSelect = useCallback((maestro: Maestro) => {
   159→    setSelectedMaestro(maestro);
   160→    setStep('mode');
   161→  }, []);
   162→
   163→  const handleModeSelect = useCallback((mode: 'voice' | 'chat') => {
   164→    if (selectedMaestro) {
   165→      onConfirm(selectedMaestro, mode);
   166→      // Reset state
   167→      setStep('subject');
   168→      setSelectedSubject(null);
   169→      setSelectedMaestro(null);
   170→    }
   171→  }, [selectedMaestro, onConfirm]);
   172→
   173→  const handleBack = useCallback(() => {
   174→    if (step === 'mode') {
   175→      // If we auto-selected maestro, go back to subject
   176→      if (availableMaestri.length === 1) {
   177→        setStep('subject');
   178→        setSelectedMaestro(null);
   179→        setSelectedSubject(null);
   180→      } else {
   181→        setStep('maestro');
   182→        setSelectedMaestro(null);
   183→      }
   184→    } else if (step === 'maestro') {
   185→      setStep('subject');
   186→      setSelectedSubject(null);
   187→    }
   188→  }, [step, availableMaestri.length]);
   189→
   190→  const handleClose = useCallback(() => {
   191→    setStep('subject');
   192→    setSelectedSubject(null);
   193→    setSelectedMaestro(null);
   194→    onClose();
   195→  }, [onClose]);
   196→
   197→  if (!isOpen) return null;
   198→
   199→  return (
   200→    <AnimatePresence>
   201→      <motion.div
   202→        initial={{ opacity: 0 }}
   203→        animate={{ opacity: 1 }}
   204→        exit={{ opacity: 0 }}
   205→        className="fixed inset-0 z-50 flex items-center justify-center bg-black/50 p-4"
   206→        onClick={handleClose}
   207→      >
   208→        <motion.div
   209→          ref={dialogRef}
   210→          role="dialog"
   211→          aria-modal="true"
   212→          aria-labelledby="dialog-title"
   213→          tabIndex={-1}
   214→          initial={{ scale: 0.95, opacity: 0 }}
   215→          animate={{ scale: 1, opacity: 1 }}
   216→          exit={{ scale: 0.95, opacity: 0 }}
   217→          onClick={(e) => e.stopPropagation()}
   218→          className="bg-white dark:bg-slate-900 rounded-2xl max-w-2xl w-full max-h-[85vh] overflow-hidden flex flex-col shadow-xl focus:outline-none"
   219→        >
   220→          {/* Header */}
   221→          <div className="flex items-center justify-between p-4 border-b border-slate-200 dark:border-slate-700">
   222→            <div className="flex items-center gap-2">
   223→              {step === 'subject' && <BookOpen className="h-5 w-5 text-accent-themed" />}
   224→              {step === 'maestro' && <GraduationCap className="h-5 w-5 text-accent-themed" />}
   225→              {step === 'mode' && <Mic className="h-5 w-5 text-accent-themed" />}
   226→              <h2 id="dialog-title" className="text-lg font-semibold">
   227→                {step === 'subject' && `Crea ${toolLabel} - Scegli Materia`}
   228→                {step === 'maestro' && `Crea ${toolLabel} - Scegli Professore`}
   229→                {step === 'mode' && `Crea ${toolLabel} - Scegli Modalità`}
   230→              </h2>
   231→            </div>
   232→            <button
   233→              onClick={handleClose}
   234→              className="p-2 rounded-full hover:bg-slate-100 dark:hover:bg-slate-800 transition-colors"
   235→              aria-label="Chiudi"
   236→            >
   237→              <X className="h-5 w-5" />
   238→            </button>
   239→          </div>
   240→
   241→          {/* Content */}
   242→          <div className="flex-1 overflow-y-auto p-4">
   243→            <AnimatePresence mode="wait">
   244→              {/* Step 1: Subject Selection */}
   245→              {step === 'subject' && (
   246→                <motion.div
   247→                  key="subject"
   248→                  initial={{ opacity: 0, x: -20 }}
   249→                  animate={{ opacity: 1, x: 0 }}
   250→                  exit={{ opacity: 0, x: 20 }}
   251→                >
   252→                  <p className="text-slate-600 dark:text-slate-400 mb-4">
   253→                    Di quale materia vuoi fare {toolLabel.toLowerCase()}?
   254→                  </p>
   255→                  <div className="grid grid-cols-3 gap-2">
   256→                    {allSubjects.map((subject) => (
   257→                      <button
   258→                        key={subject}
   259→                        onClick={() => handleSubjectSelect(subject)}
   260→                        className={cn(
   261→                          'p-3 text-sm rounded-lg border-2 transition-all font-medium',
   262→                          'bg-white dark:bg-slate-800 border-slate-200 dark:border-slate-700',
   263→                          'hover:border-accent-themed hover:bg-accent-themed/10'
   264→                        )}
   265→                      >
   266→                        {getSubjectLabel(subject)}
   267→                      </button>
   268→                    ))}
   269→                  </div>
   270→                </motion.div>
   271→              )}
   272→
   273→              {/* Step 2: Maestro Selection */}
   274→              {step === 'maestro' && (
   275→                <motion.div
   276→                  key="maestro"
   277→                  initial={{ opacity: 0, x: -20 }}
   278→                  animate={{ opacity: 1, x: 0 }}
   279→                  exit={{ opacity: 0, x: 20 }}
   280→                >
   281→                  <p className="text-slate-600 dark:text-slate-400 mb-4">
   282→                    {selectedSubject && availableMaestri.length > 0 ? (
   283→                      <>Scegli il Professore per <span className="font-semibold text-accent-themed">{getSubjectLabel(selectedSubject)}</span>:</>
   284→                    ) : (
   285→                      <>Nessun professore specifico per questa materia. Scegli tra tutti i Professori:</>
   286→                    )}
   287→                  </p>
   288→                  <div className="space-y-2">
   289→                    {(availableMaestri.length > 0 ? availableMaestri : allMaestri).map((maestro) => (
   290→                      <button
   291→                        key={maestro.id}
   292→                        onClick={() => handleMaestroSelect(maestro)}
   293→                        className="w-full p-4 flex items-center gap-3 rounded-lg border-2 border-slate-200 dark:border-slate-700 hover:border-accent-themed hover:bg-accent-themed/5 transition-all text-left"
   294→                      >
   295→                        <div className="w-12 h-12 rounded-full overflow-hidden shadow-md flex-shrink-0">
   296→                          <Image
   297→                            src={maestro.avatar}
   298→                            alt={maestro.name}
   299→                            width={48}
   300→                            height={48}
   301→                            className="w-full h-full object-cover"
   302→                          />
   303→                        </div>
   304→                        <div className="flex-1">
   305→                          <p className="font-semibold">{maestro.name}</p>
   306→                          <p className="text-sm text-slate-500">{maestro.specialty}</p>
   307→                        </div>
   308→                        <ArrowRight className="h-5 w-5 text-accent-themed" />
   309→                      </button>
   310→                    ))}
   311→                  </div>
   312→                </motion.div>
   313→              )}
   314→
   315→              {/* Step 3: Mode Selection */}
   316→              {step === 'mode' && selectedMaestro && (
   317→                <motion.div
   318→                  key="mode"
   319→                  initial={{ opacity: 0, x: -20 }}
   320→                  animate={{ opacity: 1, x: 0 }}
   321→                  exit={{ opacity: 0, x: 20 }}
   322→                >
   323→                  <div className="flex items-center gap-3 mb-4 p-3 bg-slate-50 dark:bg-slate-800 rounded-lg">
   324→                    <div className="w-10 h-10 rounded-full overflow-hidden">
   325→                      <Image
   326→                        src={selectedMaestro.avatar}
   327→                        alt={selectedMaestro.name}
   328→                        width={40}
   329→                        height={40}
   330→                        className="w-full h-full object-cover"
   331→                      />
