    19→
    20→/**
    21→ * Hook to manage conversation inactivity tracking
    22→ * - Registers timeout callback
    23→ * - Tracks activity on conversation changes
    24→ * - Auto-generates summary on browser/tab close
    25→ */
    26→export function useConversationInactivity(
    27→  isActive: boolean,
    28→  activeCharacter: ActiveCharacter | null,
    29→  conversationsByCharacter: ConversationsByCharacter
    30→) {
    31→  // Register inactivity timeout callback on mount
    32→  useEffect(() => {
