    34→      logger.info('Conversation timed out due to inactivity', { conversationId });
    35→      await endConversationWithSummary(conversationId);
    36→    });
    37→
    38→    return () => {
    39→      inactivityMonitor.stopAll();
    40→    };
    41→  }, []);
    42→
    43→  // Track activity when conversation starts or changes
    44→  useEffect(() => {
    45→    if (!isActive || !activeCharacter) return;
    46→
    47→    const userId = getOrCreateUserId();
    48→    if (!userId) return;
    49→
    50→    const conversationId = conversationsByCharacter[activeCharacter.id]?.conversationId;
    51→    if (!conversationId) return;
    52→
    53→    // Start/reset inactivity timer
    54→    inactivityMonitor.trackActivity(conversationId, userId, activeCharacter.id);
    55→    logger.debug('Tracking conversation activity', { conversationId, characterId: activeCharacter.id });
    56→  }, [isActive, activeCharacter, conversationsByCharacter]);
    57→
    58→  // Auto-generate summary when user closes browser/tab
    59→  useEffect(() => {
    60→    if (!isActive || !activeCharacter) return;
    61→
    62→    const userId = getOrCreateUserId();
    63→    if (!userId) return;
    64→
    65→    const conversationId = conversationsByCharacter[activeCharacter.id]?.conversationId;
    66→    if (!conversationId) return;
    67→
