  try {
    const memory = await loadPreviousContext(userId, maestroId);
    if (memory.recentSummary || memory.keyFacts.length > 0) {
      enhancedSystemPrompt = enhanceSystemPrompt({
        basePrompt: enhancedSystemPrompt,
