const [useWebSpeechFallback, setUseWebSpeechFallback] = useState(false);
const [connectionInfo, setConnectionInfo] = useState<VoiceConnectionInfo | null>(null);
const [hasCheckedAzure, setHasCheckedAzure] = useState(false);
const lastTranscriptRef = useRef<string | null>(null);

// ========== SINGLE VOICE SESSION FOR ALL ONBOARDING STEPS ==========
const voiceSession = useVoiceSession({
  noiseReductionType: 'far_field',
  onError: (error) => {
    const message = error instanceof Error ? error.message : String(error);
    logger.error('[WelcomePage] Voice error', { message });
    setUseWebSpeechFallback(true);
  },
  onTranscript: (role, text) => {
    // Deduplicate transcripts
    if (lastTranscriptRef.current === text.substring(0, 50)) return;
    lastTranscriptRef.current = text.substring(0, 50);
    addVoiceTranscript(role as 'user' | 'assistant', text);
  },
});

toolUseResult.newString:
// Track if we should use Web Speech fallback (when Azure unavailable)
const [useWebSpeechFallback, setUseWebSpeechFallback] = useState(false);
const [connectionInfo, setConnectionInfo] = useState<VoiceConnectionInfo | null>(null);
const [hasCheckedAzure, setHasCheckedAzure] = useState(false);
const lastTranscriptRef = useRef<string | null>(null);

// Voice reconnection logic
const voiceRetryAttemptsRef = useRef(0);
const voiceRetryTimeoutRef = useRef<NodeJS.Timeout | null>(null);
const MAX_VOICE_RETRIES = 3;
const VOICE_RETRY_DELAY_MS = 2000; // Start with 2 seconds

// ========== SINGLE VOICE SESSION FOR ALL ONBOARDING STEPS ==========
const voiceSession = useVoiceSession({
  noiseReductionType: 'far_field',
  onError: (error) => {
    const message = error instanceof Error ? error.message : String(error);
    logger.error('[WelcomePage] Voice error', {
      message,
      retryAttempt: voiceRetryAttemptsRef.current,
      maxRetries: MAX_VOICE_RETRIES,
    });

    // Retry logic with exponential backoff
    if (voiceRetryAttemptsRef.current < MAX_VOICE_RETRIES) {
      voiceRetryAttemptsRef.current++;
      const retryDelay = VOICE_RETRY_DELAY_MS * voiceRetryAttemptsRef.current;

      logger.info('[WelcomePage] Attempting voice reconnection', {
        attempt: voiceRetryAttemptsRef.current,
        maxRetries: MAX_VOICE_RETRIES,
        delayMs: retryDelay,
      });

      // Clear any existing timeout
      if (voiceRetryTimeoutRef.current) {
        clearTimeout(voiceRetryTimeoutRef.current);
      }

      // Schedule reconnection attempt
      voiceRetryTimeoutRef.current = setTimeout(() => {
        logger.info('[WelcomePage] Reconnecting voice session...');
        // The useVoiceSession hook will handle the actual reconnection
        // when connect() is called again by the component
      }, retryDelay);
    } else {
      // Max retries exceeded - fallback permanently to Web Speech
      logger.warn('[WelcomePage] Max voice retries exceeded, falling back to Web Speech', {
        totalAttempts: voiceRetryAttemptsRef.current,
      });
      setUseWebSpeechFallback(true);
    }
  },
  onTranscript: (role, text) => {
    // Voice session working - reset retry counter
    voiceRetryAttemptsRef.current = 0;

    // Deduplicate transcripts
    if (lastTranscriptRef.current === text.substring(0, 50)) return;
    lastTranscriptRef.current = text.substring(0, 50);
    addVoiceTranscript(role as 'user' | 'assistant', text);
  },
});

