     1→// ============================================================================
     2→// TELEMETRY STORE (Zustand)
     3→// Client-side telemetry collection and batching
     4→// ============================================================================
     5→
     6→import { create } from 'zustand';
     7→// Issue #64: Removed persist() - telemetry uses server API
     8→import { nanoid } from 'nanoid';
     9→import { logger } from '@/lib/logger';
    10→import type {
    11→  TelemetryEvent,
    12→  TelemetryCategory,
    13→  TelemetryConfig,
    14→  UsageStats,
    15→} from './types';
    16→
    17→// ============================================================================
    18→// STORE STATE
    19→// ============================================================================
    20→
    21→interface TelemetryState {
    22→  // Configuration
    23→  config: TelemetryConfig;
    24→
    25→  // Session management
    26→  sessionId: string;
    27→  sessionStartedAt: Date | null;
    28→
    29→  // Event queue (batched before sending)
    30→  eventQueue: TelemetryEvent[];
    31→
    32→  // Local stats (updated in real-time)
    33→  localStats: {
    34→    todaySessions: number;
    35→    todayStudyMinutes: number;
    36→    todayPageViews: number;
    37→    todayQuestions: number;
    38→    lastActivityAt: Date | null;
    39→  };
    40→
    41→  // Cached usage stats from server
    42→  usageStats: UsageStats | null;
    43→  lastFetchedAt: Date | null;
    44→
    45→  // Actions
    46→  trackEvent: (
    47→    category: TelemetryCategory,
    48→    action: string,
    49→    label?: string,
    50→    value?: number,
    51→    metadata?: Record<string, string | number | boolean>
    52→  ) => void;
    53→
    54→  startSession: () => void;
    55→  endSession: () => void;
    56→
    57→  flushEvents: () => Promise<void>;
    58→
    59→  updateConfig: (config: Partial<TelemetryConfig>) => void;
    60→
    61→  fetchUsageStats: () => Promise<void>;
    62→
    63→  clearLocalData: () => void;
    64→}
    65→
    66→// ============================================================================
    67→// DEFAULT CONFIG
    68→// ============================================================================
    69→
    70→const DEFAULT_CONFIG: TelemetryConfig = {
    71→  enabled: true,
    72→  sampleRate: 1.0,        // Capture all events
    73→  batchSize: 10,          // Send every 10 events
    74→  flushIntervalMs: 30000, // Auto-flush every 30 seconds
    75→  maxQueueSize: 100,      // Max 100 events in queue
    76→  excludeCategories: [],
    77→};
    78→
    79→// ============================================================================
    80→// HELPERS
    81→// ============================================================================
    82→
    83→function generateSessionId(): string {
    84→  // Use nanoid for cryptographically secure random strings
    85→  return `sess_${Date.now()}_${nanoid(7)}`;
    86→}
    87→
    88→function isSameDay(date1: Date | string | null, date2: Date): boolean {
    89→  if (!date1) return false;
    90→  // Handle string dates from JSON serialization
    91→  const d1 = typeof date1 === 'string' ? new Date(date1) : date1;
    92→  if (isNaN(d1.getTime())) return false;
    93→  return (
    94→    d1.getFullYear() === date2.getFullYear() &&
    95→    d1.getMonth() === date2.getMonth() &&
    96→    d1.getDate() === date2.getDate()
    97→  );
    98→}
    99→
   100→// ============================================================================
   101→// STORE
   102→// ============================================================================
   103→
   104→export const useTelemetryStore = create<TelemetryState>()(
   105→    (set, get) => ({
   106→      // Initial state
   107→      config: DEFAULT_CONFIG,
   108→      sessionId: generateSessionId(),
   109→      sessionStartedAt: null,
   110→      eventQueue: [],
   111→      localStats: {
   112→        todaySessions: 0,
   113→        todayStudyMinutes: 0,
   114→        todayPageViews: 0,
   115→        todayQuestions: 0,
   116→        lastActivityAt: null,
   117→      },
   118→      usageStats: null,
   119→      lastFetchedAt: null,
   120→
   121→      // Track an event
   122→      trackEvent: (category, action, label, value, metadata) => {
   123→        const state = get();
   124→
   125→        // Check if telemetry is enabled
   126→        if (!state.config.enabled) return;
   127→
   128→        // Check if category is excluded
   129→        if (state.config.excludeCategories.includes(category)) return;
   130→
   131→        // Apply sample rate
   132→        if (Math.random() > state.config.sampleRate) return;
   133→
   134→        const event: TelemetryEvent = {
   135→          id: `evt_${Date.now()}_${nanoid(7)}`,
   136→          timestamp: new Date(),
   137→          category,
   138→          action,
   139→          label,
   140→          value,
   141→          metadata,
   142→          sessionId: state.sessionId,
   143→        };
   144→
   145→        // Add to queue
   146→        const newQueue = [...state.eventQueue, event];
   147→
   148→        // Trim if exceeds max size
   149→        const trimmedQueue = newQueue.length > state.config.maxQueueSize
   150→          ? newQueue.slice(-state.config.maxQueueSize)
   151→          : newQueue;
   152→
   153→        // Update local stats
   154→        const today = new Date();
   155→        const localStats = { ...state.localStats };
   156→
   157→        if (!isSameDay(localStats.lastActivityAt, today)) {
   158→          // Reset daily stats
   159→          localStats.todaySessions = 0;
   160→          localStats.todayStudyMinutes = 0;
   161→          localStats.todayPageViews = 0;
   162→          localStats.todayQuestions = 0;
   163→        }
   164→
   165→        localStats.lastActivityAt = today;
   166→
   167→        // Track specific actions
   168→        if (category === 'navigation' && action === 'page_view') {
   169→          localStats.todayPageViews++;
   170→        }
   171→        if (category === 'conversation' && action === 'question_asked') {
   172→          localStats.todayQuestions++;
   173→        }
   174→        if (category === 'conversation' && action === 'session_ended' && value) {
   175→          localStats.todayStudyMinutes += Math.round(value / 60); // value in seconds
   176→        }
   177→
   178→        set({
   179→          eventQueue: trimmedQueue,
   180→          localStats,
   181→        });
   182→
   183→        // Auto-flush if batch size reached
   184→        if (trimmedQueue.length >= state.config.batchSize) {
   185→          get().flushEvents();
   186→        }
   187→      },
   188→
   189→      // Start a new session
   190→      startSession: () => {
   191→        const state = get();
   192→        const today = new Date();
   193→
   194→        let localStats = { ...state.localStats };
   195→
   196→        // Reset daily stats if new day
   197→        if (!isSameDay(localStats.lastActivityAt, today)) {
   198→          localStats = {
   199→            todaySessions: 1,
   200→            todayStudyMinutes: 0,
   201→            todayPageViews: 0,
   202→            todayQuestions: 0,
   203→            lastActivityAt: today,
   204→          };
   205→        } else {
   206→          localStats.todaySessions++;
   207→          localStats.lastActivityAt = today;
   208→        }
   209→
   210→        set({
   211→          sessionId: generateSessionId(),
   212→          sessionStartedAt: new Date(),
   213→          localStats,
   214→        });
   215→
   216→        // Track session start event
   217→        get().trackEvent('navigation', 'session_started');
   218→      },
   219→
   220→      // End current session
   221→      endSession: () => {
   222→        const state = get();
   223→
   224→        if (state.sessionStartedAt) {
   225→          const durationSeconds = Math.round(
   226→            (Date.now() - state.sessionStartedAt.getTime()) / 1000
   227→          );
   228→
   229→          get().trackEvent('navigation', 'session_ended', undefined, durationSeconds);
   230→        }
   231→
   232→        // Flush remaining events
   233→        get().flushEvents();
   234→
   235→        set({
   236→          sessionStartedAt: null,
   237→        });
   238→      },
   239→
   240→      // Flush events to server
   241→      flushEvents: async () => {
   242→        const state = get();
   243→
   244→        if (state.eventQueue.length === 0) return;
   245→
   246→        const eventsToSend = [...state.eventQueue];
   247→
   248→        // Clear queue immediately (optimistic)
   249→        set({ eventQueue: [] });
   250→
   251→        try {
   252→          await fetch('/api/telemetry/events', {
   253→            method: 'POST',
   254→            headers: { 'Content-Type': 'application/json' },
   255→            body: JSON.stringify({ events: eventsToSend }),
   256→          });
   257→        } catch (error) {
   258→          // On failure, add events back to queue
   259→          set((s) => ({
   260→            eventQueue: [...eventsToSend, ...s.eventQueue].slice(-s.config.maxQueueSize),
   261→          }));
   262→          logger.error('Telemetry flush failed', { error });
   263→        }
   264→      },
   265→
   266→      // Update configuration
   267→      updateConfig: (configUpdates) => {
   268→        set((state) => ({
   269→          config: { ...state.config, ...configUpdates },
   270→        }));
   271→      },
   272→
   273→      // Fetch usage stats from server
   274→      fetchUsageStats: async () => {
   275→        try {
   276→          const response = await fetch('/api/telemetry/stats');
   277→
   278→          if (response.ok) {
   279→            const stats = await response.json();
   280→
   281→            set({
   282→              usageStats: {
   283→                ...stats,
   284→                lastUpdated: new Date(stats.lastUpdated),
   285→              },
   286→              lastFetchedAt: new Date(),
   287→            });
   288→          }
   289→        } catch (error) {
   290→          logger.error('Failed to fetch usage stats', { error });
