     1→'use client';
     2→
     3→/**
     4→ * Client-side error logger - Captures all browser errors and sends to server
     5→ *
     6→ * Captures:
     7→ * - Unhandled errors (window.onerror)
     8→ * - Unhandled promise rejections
     9→ * - React error boundaries
    10→ * - Console.error calls
    11→ * - Network fetch errors
    12→ *
    13→ * Usage: Import once in layout.tsx or _app.tsx
    14→ *   import '@/lib/client-error-logger';
    15→ */
    16→
    17→type LogLevel = 'error' | 'warn' | 'info' | 'debug';
    18→
    19→interface ClientLogEntry {
    20→  level: LogLevel;
    21→  message: string;
    22→  context?: Record<string, unknown>;
    23→  stack?: string;
    24→  url?: string;
    25→}
    26→
    27→const LOG_ENDPOINT = '/api/debug/log';
    28→
    29→// Debounce to avoid flooding
    30→const sentErrors = new Set<string>();
    31→const MAX_ERRORS_PER_SESSION = 500;
    32→let errorCount = 0;
    33→
    34→/**
    35→ * Send log to server
    36→ */
    37→async function sendLog(entry: ClientLogEntry): Promise<void> {
    38→  if (typeof window === 'undefined') return;
    39→  if (errorCount >= MAX_ERRORS_PER_SESSION) return;
    40→
    41→  // Dedupe by message
    42→  const key = `${entry.level}:${entry.message}`;
    43→  if (sentErrors.has(key)) return;
    44→  sentErrors.add(key);
    45→  errorCount++;
    46→
    47→  try {
    48→    await fetch(LOG_ENDPOINT, {
    49→      method: 'POST',
    50→      headers: { 'Content-Type': 'application/json' },
    51→      body: JSON.stringify({
    52→        ...entry,
    53→        url: window.location.href,
    54→      }),
    55→    });
    56→  } catch {
    57→    // Can't log the logger failing
    58→  }
    59→}
    60→
    61→/**
    62→ * Initialize error capturing
    63→ */
    64→function initClientErrorLogger(): void {
    65→  if (typeof window === 'undefined') return;
    66→
    67→  // Skip in production
    68→  if (process.env.NODE_ENV !== 'development') return;
    69→
    70→  // Global error handler
    71→  const originalOnError = window.onerror;
    72→  window.onerror = (message, source, lineno, colno, error) => {
    73→    sendLog({
    74→      level: 'error',
    75→      message: String(message),
    76→      stack: error?.stack,
    77→      context: {
    78→        source,
    79→        line: lineno,
    80→        column: colno,
    81→      },
    82→    });
    83→
    84→    if (originalOnError) {
    85→      return originalOnError(message, source, lineno, colno, error);
    86→    }
    87→    return false;
    88→  };
    89→
    90→  // Unhandled promise rejections
    91→  window.addEventListener('unhandledrejection', (event) => {
    92→    const reason = event.reason;
    93→    sendLog({
    94→      level: 'error',
    95→      message: `Unhandled Promise Rejection: ${reason?.message || String(reason)}`,
    96→      stack: reason?.stack,
    97→      context: {
    98→        type: 'unhandledrejection',
    99→      },
   100→    });
   101→  });
   102→
   103→  // Intercept console.error
   104→  const originalConsoleError = console.error;
   105→  console.error = (...args) => {
   106→    const message = args.map(arg => {
   107→      if (arg instanceof Error) return arg.message;
